mapper.select:
SELECT SCORE_DELTA
FROM COMPETENCY_ACTION_SCORE_POLICY
WHERE COMPETENCY_ID = #{competencyId}
  AND CALC_TYPE = #{calcType}
  AND USE_YN = 'Y'

SELECT COUNT(*)
FROM CAREER_RECOMMENDATION cr
JOIN CAREER_DIAGNOSIS cd
  ON cd.DIAGNOSIS_ID = cr.DIAGNOSIS_ID
WHERE cd.USER_ID = #{userId}
  AND cr.COURSE_ID = #{courseId}

SELECT COUNT(*)
FROM COMPETENCY_SCORE_HISTORY
WHERE USER_ID = #{userId}
  AND COMPETENCY_ID = #{competencyId}
  AND CALC_TYPE = #{calcType}
  AND (
      (#{referenceType, jdbcType=VARCHAR} IS NULL AND REFERENCE_TYPE IS NULL)
      OR REFERENCE_TYPE = #{referenceType, jdbcType=VARCHAR}
  )
  AND (
      (#{referenceId, jdbcType=NUMERIC} IS NULL AND REFERENCE_ID IS NULL)
      OR REFERENCE_ID = #{referenceId, jdbcType=NUMERIC}
  )

mapper.insert:
INSERT INTO COMPETENCY_SCORE_HISTORY (
    HISTORY_ID,
    USER_ID,
    COMPETENCY_ID,
    SCORE,
    CALC_TYPE,
    REFERENCE_TYPE,
    REFERENCE_ID,
    CALCULATED_AT
)
SELECT
    COMPETENCY_SCORE_HISTORY_SEQ.NEXTVAL,
    #{userId},
    #{competencyId},
    LEAST(100, NVL((
        SELECT ucs.SCORE
        FROM USER_COMPETENCY_SCORE ucs
        WHERE ucs.USER_ID = #{userId}
          AND ucs.COMPETENCY_ID = #{competencyId}
    ), 70) + #{scoreDelta}),
    #{calcType},
    #{referenceType, jdbcType=VARCHAR},
    #{referenceId, jdbcType=NUMERIC},
    SYSDATE
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1
    FROM COMPETENCY_SCORE_HISTORY csh
    WHERE csh.USER_ID = #{userId}
      AND csh.COMPETENCY_ID = #{competencyId}
      AND csh.CALC_TYPE = #{calcType}
      AND (
          (#{referenceType, jdbcType=VARCHAR} IS NULL AND csh.REFERENCE_TYPE IS NULL)
          OR csh.REFERENCE_TYPE = #{referenceType, jdbcType=VARCHAR}
      )
      AND (
          (#{referenceId, jdbcType=NUMERIC} IS NULL AND csh.REFERENCE_ID IS NULL)
          OR csh.REFERENCE_ID = #{referenceId, jdbcType=NUMERIC}
      )
)
